+                        r: 0.94,
+                        g: 0.46,
+                        b: 0.26,
+                        a: 0.9,
+                    },
+                    if agent.spiked { 1.25 } else { 1.0 },
+                ),
+                palette,
+                palette_is_natural,
+            );
+            window.paint_path(path, spike_color);
+        }
+        return;
+    }
+
+    // Body shell
+    let mut body_shape = PathBuilder::fill();
+    append_capsule_polygon(
+        &mut body_shape,
+        (px_x, px_y),
+        forward,
+        right,
+        body_half_length,
